// In the module that uses {providerName}:
@Module({
  imports: [OtherModule],  // import modules that export needed providers
  providers: [MyService, MyRepository],  // register local providers
})
export class AppModule {}

// In the module that owns the provider:
@Module({
  providers: [MyService],
  exports: [MyService],  // must export to share
})
export class SharedModule {}

// In the consuming module:
@Module({
  imports: [SharedModule],  // import the module
})
export class AppModule {}

// Break circular dependency with forwardRef:
@Module({
  imports: [forwardRef(() => ModuleB)],
})
export class ModuleA {}

// In the provider:
@Injectable()
export class ServiceA {
  constructor(
    @Inject(forwardRef(() => ServiceB))
    private serviceB: ServiceB,
  ) {}
}

